import { createCanvas } from '@napi-rs/canvas';
import { Static, paintRules } from 'protomaps-leaflet';
import { LIGHT } from '@protomaps/basemaps';
import { PMTiles } from 'pmtiles';
import { open } from 'fs/promises';
import { resolve } from 'path';

// Custom file source for PMTiles  
class FileSource {
  constructor\(path\) { this.path = path; }
  async getBytes\(offset, length\) {
    const fh = await open\(this.path, 'r'\);
    const buf = Buffer.alloc\(length\);
    await fh.read\(buf, 0, length, offset\);
    await fh.close\(\);
    return { data: buf.buffer.slice\(buf.byteOffset, buf.byteOffset + buf.byteLength\) };
  }
  getKey\(\) { return this.path; }
}

const absPath = resolve\('public/tiles/taipei.pmtiles'\);
const pm = new PMTiles\(new FileSource\(absPath\)\);
const header = await pm.getHeader\(\);
console.log\('minZoom:', header.minZoom, 'maxZoom:', header.maxZoom\);
console.log\('bounds:', header.minLon, header.minLat, header.maxLon, header.maxLat\);

const s = new Static\({
  url: pm,
  paintRules: paintRules\(LIGHT\),
  labelRules: [],
  backgroundColor: LIGHT.background,
}\);

const canvas = createCanvas\(256, 256\);
const ctx = canvas.getContext\('2d'\);
const result = await s.drawContext\(ctx, 256, 256, {x: 121.565, y: 25.033}, 14\);
console.log\('rendered in', result.elapsed, 'ms'\);

import { writeFileSync } from 'fs';
const buf = canvas.toBuffer\('image/png'\);
writeFileSync\('/tmp/test-tile3.png', buf\);
console.log\('saved', buf.byteLength, 'bytes'\);
" 2>&1)

