import { createCanvas } from '@napi-rs/canvas';
import { Static, paintRules, labelRules } from 'protomaps-leaflet';
import { LIGHT } from '@protomaps/basemaps';
import { PMTiles } from 'pmtiles';
import { open } from 'fs/promises';
import { resolve } from 'path';

class FileSource {
  constructor\(path\) { this.path = path; }
  async getBytes\(offset, length\) {
    const fh = await open\(this.path, 'r'\);
    const buf = Buffer.alloc\(length\);
    await fh.read\(buf, 0, length, offset\);
    await fh.close\(\);
    return { data: buf.buffer.slice\(buf.byteOffset, buf.byteOffset + buf.byteLength\) };
  }
  getKey\(\) { return this.path; }
}

const absPath = resolve\('public/tiles/taipei.pmtiles'\);
const pm = new PMTiles\(new FileSource\(absPath\)\);

const s = new Static\({
  url: pm,
  paintRules: paintRules\(LIGHT\),
  labelRules: labelRules\(LIGHT, 'en'\),
  backgroundColor: LIGHT.background,
}\);

