// Tile count estimate for bbox 121.4-121.7, 24.9-25.2
function lng2tile\(lng, z\) { return Math.floor\(\(\(lng + 180\) / 360\) * \(1 << z\)\); }
function lat2tile\(lat, z\) { const r = lat * Math.PI / 180; return Math.floor\(\(\(1 - Math.log\(Math.tan\(r\) + 1/Math.cos\(r\)\) / Math.PI\) / 2\) * \(1 << z\)\); }
for \(let z = 15; z <= 18; z++\) {
  const xMin = lng2tile\(121.4, z\), xMax = lng2tile\(121.7, z\);
  const yMin = lat2tile\(25.2, z\), yMax = lat2tile\(24.9, z\);
  const count = \(xMax-xMin+1\)*\(yMax-yMin+1\);
  console.log\('z' + z + ': ' + count + ' tiles'\);
}
" 2>&1)
